module add (
    real a,
    real b,
    output real sum
);

  always @(*) begin
    sum = a + b;
  end

endmodule
module div (
    real a,
    real b,
    output real result
);

  always @(*) begin
    result = 0;
    if (b) begin
        result = a / b;
    end
  end

endmodule
